sed -i '/Instruction \*BoUpSLP::getInsertPos_old/,/return IP;/d' lib/Transforms/Vectorize/SLPVectorizer.cpp && \
sed -i 's/Instruction \*I = FirstInst;/Instruction \*User = FirstInst;/' lib/Transforms/Vectorize/SLPVectorizer.cpp && \
